css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { min-height: 100vh; background: #0f0a1e; font-family: -apple-system, BlinkMacSystemFont, sans-serif; display: flex; align-items: center; justify-content: center; color: white; padding: 20px; }
.game { width: 100%; max-width: 480px; }
.game-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 24px; }
h1 { font-size: 28px; font-weight: 900; }
.game-info { display: flex; gap: 16px; }
.info-item { background: rgba(255,255,255,0.07); border-radius: 12px; padding: 10px 16px; text-align: center; } .info-item span { display: block; font-size: 11px; color: rgba(255,255,255,0.5); margin-bottom: 2px; } .info-item strong { font-size: 18px; font-weight: 800; }
.board { display: grid; grid-template-columns: repeat(4, 1fr); gap: 12px; margin-bottom: 20px; }
.card { aspect-ratio: 1; border-radius: 14px; cursor: pointer; transition: transform 0.3s; transform-style: preserve-3d; position: relative; }
.card.flipped { transform: rotateY(180deg); }
.card.matched { cursor: default; }
.card-front, .card-back { position: absolute; width: 100%; height: 100%; border-radius: 14px; display: flex; align-items: center; justify-content: center; backface-visibility: hidden; }
.card-back { background: linear-gradient(135deg, #4c1d95, #6d28d9); border: 1px solid rgba(139,92,246,0.4); font-size: 32px; }
.card-front { background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.1); transform: rotateY(180deg); font-size: 36px; }
.card.matched .card-front { background: rgba(34,197,94,0.15); border-color: rgba(34,197,94,0.4); animation: matchPulse 0.4s ease; }
@keyframes matchPulse { 0%,100% { transform: rotateY(180deg) scale(1); } 50% { transform: rotateY(180deg) scale(1.08); } }
.win-screen { position: fixed; inset: 0; background: rgba(0,0,0,0.8); display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 16px; backdrop-filter: blur(10px); }
.win-emoji { font-size: 72px; } .win-screen h2 { font-size: 36px; font-weight: 900; } .win-screen p { color: rgba(255,255,255,0.7); font-size: 16px; }
.win-screen button, .new-game { padding: 14px 32px; border-radius: 14px; border: none; background: linear-gradient(135deg, #7c3aed, #a855f7); color: white; font-size: 16px; font-weight: 700; cursor: pointer; }
.new-game { display: block; margin: 0 auto; }

