const emojis = ['🐶','🐱','🐭','🐹','🐰','🦊','🐻','🐼'];
let flipped = [], matched = 0, moves = 0, timerInterval = null, seconds = 0, locked = false;
function startGame() {
  const cards = [...emojis, ...emojis].sort(() => Math.random() - 0.5);
  flipped = []; matched = 0; moves = 0; seconds = 0; locked = false;
  document.getElementById('moves').textContent = 0;
  document.getElementById('matches').textContent = '0/8';
  document.getElementById('timer').textContent = '0:00';
  document.getElementById('win').style.display = 'none';
  clearInterval(timerInterval);
  timerInterval = setInterval(() => { seconds++; const m = Math.floor(seconds/60); const s = seconds%60; document.getElementById('timer').textContent = m+':'+(s<10?'0':'')+s; }, 1000);
  document.getElementById('board').innerHTML = cards.map((emoji, i) => `
    <div class="card" id="card-${i}" onclick="flip(${i},'${emoji}')">
      <div class="card-back">❓</div>
      <div class="card-front">${emoji}</div>
    </div>
  `).join('');
}
function flip(i, emoji) {
  const card = document.getElementById('card-'+i);
  if (locked || card.classList.contains('flipped') || card.classList.contains('matched')) return;
  card.classList.add('flipped');
  flipped.push({ i, emoji, card });
  if (flipped.length === 2) {
    locked = true; moves++;
    document.getElementById('moves').textContent = moves;
    if (flipped[0].emoji === flipped[1].emoji) {
      flipped.forEach(f => f.card.classList.add('matched'));
      matched++;
      document.getElementById('matches').textContent = matched+'/8';
      flipped = []; locked = false;
      if (matched === 8) { clearInterval(timerInterval); const m=Math.floor(seconds/60),s=seconds%60; document.getElementById('win-msg').textContent = moves+' hamlede, '+(m>0?m+'dk ':'')+s+'sn'de tamamladın!'; document.getElementById('win').style.display = 'flex'; }
    } else {
      setTimeout(() => { flipped.forEach(f => f.card.classList.remove('flipped')); flipped = []; locked = false; }, 1000);
    }
  }
}
startGame();
